# agentic_I2 skeptic-crosscheck · S18-T2-A-E3
def max_bias(pob, counts):
    num = sum(counts.values())
    return max(abs(counts[k] / num - pob[k]) for k in pob)

print(round(max_bias({"Lima": 0.5, "Cusco": 0.5}, {"Lima": 9, "Cusco": 1}), 2))

